import java.lang.reflect.*;

public class GenericMaster {

  public static Class<?> getGenericType(Field field) {
    final Type type = field.getGenericType();

      if (type == null) {
          throw new NullPointerException("field type");
      } else if (type instanceof ParameterizedType) {
        final ParameterizedType parameterizedType = (ParameterizedType) type;
        final Type rawType = parameterizedType.getRawType();
        if (rawType instanceof Class) {
            final Class<?> rawTypeAsClass = (Class<?>) rawType;
                if ("List".equals(rawTypeAsClass.getName())) {
                    return (Class<Object>) parameterizedType.getActualTypeArguments()[0];
                  }
                 }
           } 


    if (!(type instanceof Class)) {
      throw new RuntimeException(String.format("Not expecting this kind of type: %s", type));
    }

    return (Class<Object>) type;
  }

}

